const fs = require\('fs'\);
const data = JSON.parse\(fs.readFileSync\('C:/Users/Citywalker/Documents/KaiQ/Map of Meaning/visual/knowledge_map.json', 'utf8'\)\);
const nodes = data.nodes;
const edges = data.edges;

// Build child sets
const hasChildren = new Set\(edges.map\(e => e.source\)\);

// Find L4 nodes without children
const l4NoChildren = nodes.filter\(n => n.level === 4 && !hasChildren.has\(n.id\)\);
console.log\('L4 nodes without children:', l4NoChildren.length\);

// Find L4 nodes WITH children
const l4WithChildren = nodes.filter\(n => n.level === 4 && hasChildren.has\(n.id\)\);
console.log\('L4 nodes with children \(already have L5\):', l4WithChildren.length\);

// Show L4 nodes with children to identify Physics branch
console.log\('\\\\nL4 nodes already with children:'\);
l4WithChildren.forEach\(n => console.log\(n.id, n.label\)\);
")
